```class Solution {
public:
    int minLength(string s) {
        int res = s.size();
        for (int i = 0; i < s.size() - 1; i++) {
            if (s.substr(i, 2) == "AB" || s.substr(i, 2) == "CD") {
                res = min(res, minLength(s.substr(0, i) + s.substr(i + 2)));
            }
        }
        return res;
    }
};```
